diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index fdadf729fbd5..11fd44a35933 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7768,9 +7768,26 @@ static Instruction *foldFCmpReciprocalAndZero(FCmpInst &I, Instruction *LHSI,
 /// Optimize fabs(X) compared with zero.
 static Instruction *foldFabsWithFcmpZero(FCmpInst &I, InstCombinerImpl &IC) {
   Value *X;
-  if (!match(I.getOperand(0), m_FAbs(m_Value(X))))
-    return nullptr;
+  if (!match(I.getOperand(0), m_FAbs(m_Value(X)))) {
+    // Check for fabs idiom: (X >= 0.0) ? X : -X
+    // This is equivalent to fabs(X) for comparison against 0
+    Value *Cond, *TrueVal, *FalseVal;
+    if (!match(I.getOperand(0), m_Select(m_Value(Cond), m_Value(TrueVal),
+                                          m_Value(FalseVal))))
+      return nullptr;

+    // Try to match the fabs idiom pattern
+    // (fcmp oge X, 0.0) ? X : (fneg X)
+    CmpInst::Predicate Pred;
+    if (!match(Cond, m_FCmp(Pred, m_Specific(TrueVal), m_AnyZeroFP())))
+      return nullptr;
+    if (Pred != FCmpInst::FCMP_OGE && Pred != FCmpInst::FCMP_UGE)
+      return nullptr;
+    if (!match(FalseVal, m_FNeg(m_Specific(TrueVal))))
+      return nullptr;
+
+    X = TrueVal;
+  }
   const APFloat *C;
   if (!match(I.getOperand(1), m_APFloat(C)))
     return nullptr;

